local TD = TD.td1madao["ydj_dst_td1madao"] local MakePlayerCharacter = require("prefabs/player_common") local assets = { Asset("ANIM", TD.holder("anim/swap_%s_wing.zip")), Asset("ANIM", TD.holder("anim/%s_hat.zip")), Asset("ANIM", TD.holder("anim/%s_2.zip")), } table.td1madao_addAll(assets, TD.basicPlayerResource()) local prefabs = {} local start_inv = { TD.holder("%s_axe1") } local function confirmData(inst) TD.csv(inst, function(self) self:init(TD.holder("%s_exp"), 0, true, true) self:init(TD.holder("%s_lv"), 1, true, true) end) end local actions = { "attack", "chop", "chop_start", "mine", "mine_start", "hammer_start", "hammer", "hack_start", "hack", TD.holder("%s_player_gun_attack") } local function one_of_ten(inst) return TD.is_weapon(inst, TD.holder("%s_axe1")) or TD.is_weapon(inst, TD.holder("%s_axe2")) or TD.is_weapon(inst, TD.holder("%s_axe3")) or TD.is_weapon(inst, TD.holder("%s_axe4")) or TD.is_weapon(inst, TD.holder("%s_axe5")) or TD.is_weapon(inst, TD.holder("%s_axe6")) or TD.is_weapon(inst, TD.holder("%s_axe7")) or TD.is_weapon(inst, TD.holder("%s_axe8")) or TD.is_weapon(inst, TD.holder("%s_axe9")) or TD.is_weapon(inst, TD.holder("%s_axe10")) or TD.is_weapon(inst, TD.holder("%s_axe")) end local function common_postinit(inst) inst.MiniMapEntity:SetIcon(TD.holder("%s.tex")) inst.one_of_ten = one_of_ten inst:AddTag("td1madao_mod") inst:AddTag("order_category") inst:AddTag(TD.holder()) if TD.ds() then inst.AnimState:SetBuild(TD.holder("%s_2")) end  inst.hyaqkiyakou = TD.hotkey("q") inst.ystip = true inst:AddTag(TD.CHAR) inst.td1madao_prefab = TD.CHAR inst.soundsname = "willow" inst.confirmData = confirmData  TD.cRegister2(inst, { TD.mgn, TD.csv, TD.ctm }) if TD.ds() then inst.entity:AddLight() inst.Light:Enable(false) inst.Light:SetRadius(25) inst.Light:SetFalloff(.5) inst.Light:SetIntensity(.6) inst.Light:SetColour(1, 1, 1) end local setOwnerFn = function(player)  TD.G.td1madao_the_player_updated = true TD.ctm(inst):common_task(0.5, function() if player ~= inst then return end if TD.dst() then if TD.isFn(inst.setOwnerFn) then inst:RemoveEventCallback("setowner", inst.setOwnerFn) end end TD.common(inst, function() TD.cRegister2(inst, { TD.mgn, TD.csv, TD.cpr, TD.ctm, TD.csa, TD.csm, TD.cem, TD.cvm, TD.cbm, TD.cse, TD.clt }) inst:confirmData() if TD.dst() then TD.player(inst, function() TD.serverCall(TD.holder("%s_loadData"), {}) end) else local param = {} param.inst = inst TD.exeClient(TD.holder("%s_flush_fluent"), param) end if inst.hyaqkiyakou == 0 then if TD.dst() then local WOLF_VISION_COLOURCUBES = { day = "images/colour_cubes/spring_day_cc.tex", dusk = "images/colour_cubes/spring_day_cc.tex", night = "images/colour_cubes/spring_day_cc.tex", full_moon = "images/colour_cubes/spring_day_cc.tex", } local function OnIsNight(inst) TD.addC(inst, "playervision", function(comp) local nightVision = true if TheWorld.state.isnight or TheWorld:HasTag("cave") then if inst.ystip then TD.talk(inst, TD.VAR3) inst.ystip = false end comp:SetCustomCCTable(WOLF_VISION_COLOURCUBES) else nightVision = false comp:SetCustomCCTable(nil) end comp:ForceNightVision(nightVision) end) end inst:WatchWorldState("isnight", OnIsNight) inst:WatchWorldState("iscaveday", OnIsNight) inst:WatchWorldState("iscavedusk", OnIsNight) inst:WatchWorldState("iscavenight", OnIsNight) TD.latter(player, 0.5, function() if TheWorld and TheWorld.state then OnIsNight(inst) end end) inst.nightConvertor = OnIsNight else local WOLF_VISION_COLOURCUBES = { day = "images/colour_cubes/spring_day_cc.tex", dusk = "images/colour_cubes/spring_day_cc.tex", night = "images/colour_cubes/spring_day_cc.tex", full_moon = "images/colour_cubes/spring_day_cc.tex", } local function OnIsNight() local phase = GetClock().phase if not TD.GetWorld():IsCave() and phase ~= "night" then TD.addC(TD.GetWorld(), "colourcubemanager", function(comp) comp:SetOverrideColourCube(nil) end) inst.Light:Enable(false) else if inst.ystip then TD.talk(inst, TD.VAR3) inst.ystip = false end TD.addC(TD.GetWorld(), "colourcubemanager", function(comp) comp:SetOverrideColourCube("images/colour_cubes/day05_cc.tex") end) inst.Light:Enable(true) end end inst:ListenForEvent("daytime", OnIsNight, TD.GetWorld()) inst:ListenForEvent("dusktime", OnIsNight, TD.GetWorld()) inst:ListenForEvent("nighttime", OnIsNight, TD.GetWorld()) TD.latter(player, 0.5, function() if TD.GetWorld() then OnIsNight(inst) end end) inst.nightConvertor = OnIsNight end end end) end) end if TD.dst() then inst.setOwnerFn = setOwnerFn inst:ListenForEvent("setowner", inst.setOwnerFn) else setOwnerFn(inst) end end local function master_postinit(inst)  TD.loadCurrentAttribute(inst) local arr = {} arr.health = TD.CONST.MAX_HEALTH arr.hunger = TD.CONST.MAX_HUNGER arr.sanity = TD.CONST.MAX_SANITY TD.writeAtt(inst, arr) TD.getC(inst, "eater", function(comp) comp:SetOnEatFn(function(inst, food) TD.hasC(food, "edible", function(comp) local expNum = (comp.healthvalue and (comp.healthvalue < 0 and 0 or comp.healthvalue) or 0) * 0.5 + (comp.hungervalue and (comp.hungervalue < 0 and 0 or comp.hungervalue) or 0) * 0.02 + (comp.sanityvalue and (comp.sanityvalue < 0 and 0 or comp.sanityvalue) or 0) * 0.7 expNum = math.floor(expNum) if expNum > 0 then TD[TD.holder("%s_obtainExp")](inst, expNum) end end) end) end)  inst.has_wing = false  TD.addC(inst, "sanity", function(comp) comp.night_drain_mult = -0.25 end)  local function reload_anim() TD.latter(inst, 0, function() TD[TD.holder("%s_hat")](inst) local old_state_fn = inst.sg.GoToState inst.sg.GoToState = function(self, frame, ...) local result = old_state_fn(self, frame, ...) if inst.prefab == TD.CHAR and one_of_ten(inst) and TD.server() then if not table.td1madao_contain(actions, frame) then if not inst.has_wing then inst.showBackWeapon() inst.AnimState:OverrideSymbol("swap_object", TD.holder("%s_none"), "swap_weapon") end else if inst.has_wing then inst.hideBackWeapon() inst.AnimState:OverrideSymbol("swap_object", TD.holder("%s_axe"), "swap_weapon") end end end return result end end) end if TD.ds() then local old = inst.SetStateGraph inst.SetStateGraph = function(self, name, ...) reload_anim() old(self, name, ...) end end if TD.dst() then inst:ListenForEvent("respawnfromghost", function(inst, data) TD.latter(inst, 5, function() inst.has_wing = true inst.hideBackWeapon() inst.AnimState:OverrideSymbol("swap_object", TD.holder("%s_axe"), "swap_weapon") TD[TD.holder("%s_hat")](inst) TD.csa(inst):flush() reload_anim() end) end) end  inst.hideBackWeapon = function() if not inst.has_wing then return end TD[TD.holder("%s_withdrawWing")](inst) inst.has_wing = false end inst.showBackWeapon = function() if inst.has_wing then return end TD[TD.holder("%s_wing")](inst) inst.has_wing = true end reload_anim() end if TD.dst() then return MakePlayerCharacter(TD.CHAR, prefabs, assets, common_postinit, master_postinit, start_inv) else return MakePlayerCharacter(TD.CHAR, prefabs, assets, function(inst) common_postinit(inst) master_postinit(inst) end, start_inv) end 